+        #[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
+        pub unsafe extern "C" fn $name(
+            _key: *const c_char,
+            _result: *mut c_void,
+            _buffer: *mut c_char,
+            _buflen: usize,
+            errnop: *mut c_int,
+        ) -> c_int {
+            unsafe { nss_set_errnop_enoent(errnop) };
+            NSS_STATUS_NOTFOUND
+        }
+    };
+}
